public class MaxSumWindow {
    public static int maxSum(int[] nums, int k) {
        int windowSum = 0;
        // Build first window:
        for (int i = 0; i < k; i++) windowSum += nums[i];
        int maxSum = windowSum;
        // Slide window:
        for (int i = k; i < nums.length; i++) {
            windowSum += nums[i] - nums[i - k]; // add right, remove left
            maxSum = Math.max(maxSum, windowSum);
        }
        return maxSum;
    }
    public static void main(String[] args) {
        System.out.println(maxSum(new int[]{2,3,4,1,5}, 2)); // 9
        System.out.println(maxSum(new int[]{1,9,7,2,3}, 3)); // 19
        System.out.println("O(n) time, O(1) space");
    }
}

