public class MinSizeSubarraySum {
    public static int minSubArrayLen(int target, int[] nums) {
        int lo = 0, windowSum = 0, minLen = Integer.MAX_VALUE;
        for (int hi = 0; hi < nums.length; hi++) {
            windowSum += nums[hi]; // expand right
            // Shrink left while condition is met (sum >= target):
            while (windowSum >= target) {
                minLen = Math.min(minLen, hi - lo + 1);
                windowSum -= nums[lo++]; // shrink left
            }
        }
        return minLen == Integer.MAX_VALUE ? 0 : minLen;
    }
    public static void main(String[] args) {
        System.out.println(minSubArrayLen(7, new int[]{2,3,1,2,4,3})); // 2
        System.out.println(minSubArrayLen(4, new int[]{1,4,4}));       // 1
        System.out.println(minSubArrayLen(11, new int[]{1,1,1,1,1,1})); // 0
        System.out.println("O(n) — lo and hi each traverse array once");
    }
}

