import java.util.*;
public class AtMostKDistinct {
    static int lengthOfLongestSubstringKDistinct(String s, int k) {
        Map<Character, Integer> freq = new HashMap<>();
        int lo = 0, maxLen = 0;
        for (int hi = 0; hi < s.length(); hi++) {
            char c = s.charAt(hi);
            freq.put(c, freq.getOrDefault(c, 0) + 1); // expand
            // Shrink while more than k distinct chars:
            while (freq.size() > k) {
                char left = s.charAt(lo);
                freq.put(left, freq.get(left) - 1);
                if (freq.get(left) == 0) freq.remove(left);
                lo++;
            }
            maxLen = Math.max(maxLen, hi - lo + 1);
        }
        return maxLen;
    }
    public static int lengthOfLongestSubstringTwoDistinct(String s) {
        return lengthOfLongestSubstringKDistinct(s, 2);
    }
    public static void main(String[] args) {
        System.out.println(lengthOfLongestSubstringTwoDistinct("eceba"));   // 3
        System.out.println(lengthOfLongestSubstringTwoDistinct("ccaabbb")); // 5
        System.out.println("Also works for k distinct: parameterize k");
    }
}

