public class LongestRepeatingChar {
    public static int characterReplacement(String s, int k) {
        int[] freq = new int[26];
        int lo = 0, maxFreq = 0, maxLen = 0;
        for (int hi = 0; hi < s.length(); hi++) {
            freq[s.charAt(hi) - 'A']++;
            maxFreq = Math.max(maxFreq, freq[s.charAt(hi) - 'A']);
            // Invalid: replacements needed = windowSize - maxFreq > k
            if ((hi - lo + 1) - maxFreq > k) {
                freq[s.charAt(lo) - 'A']--;
                lo++;
                // Note: maxFreq may be stale here, but it's OK
                // (we never need to decrease maxLen)
            }
            maxLen = Math.max(maxLen, hi - lo + 1);
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(characterReplacement("AABABBA", 1)); // 4
        System.out.println(characterReplacement("ABAB", 2));    // 4
        System.out.println("O(n) time, O(1) space (26-char array)");
    }
}

