import java.util.*;
public class ContainsDuplicate2 {
    public static boolean containsNearbyDuplicate(int[] nums, int k) {
        Set<Integer> window = new HashSet<>(); // sliding window of size k
        for (int i = 0; i < nums.length; i++) {
            if (window.contains(nums[i])) return true; // duplicate within k distance
            window.add(nums[i]);
            if (window.size() > k) {
                window.remove(nums[i - k]); // remove element k positions back
            }
        }
        return false;
    }
    public static void main(String[] args) {
        System.out.println(containsNearbyDuplicate(new int[]{1,2,3,1}, 3));     // true
        System.out.println(containsNearbyDuplicate(new int[]{1,0,1,1}, 1));     // true
        System.out.println(containsNearbyDuplicate(new int[]{1,2,3,1,2,3}, 2)); // false
        System.out.println("O(n) time, O(k) space");
    }
}

