import java.util.*;
public class SubarraySumK {
    // Prefix sum + HashMap: prefixSum[j] - prefixSum[i] = k
    // → we need prefixSum[i] = prefixSum[j] - k
    // Count how many times we've seen each prefix sum
    public static int subarraySum(int[] nums, int k) {
        Map<Integer, Integer> prefixCount = new HashMap<>();
        prefixCount.put(0, 1); // empty subarray has sum 0
        int sum = 0, count = 0;
        for (int num : nums) {
            sum += num;
            // If (sum - k) was seen before, those are valid subarrays:
            count += prefixCount.getOrDefault(sum - k, 0);
            prefixCount.put(sum, prefixCount.getOrDefault(sum, 0) + 1);
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(subarraySum(new int[]{1,1,1}, 2));   // 2
        System.out.println(subarraySum(new int[]{1,2,3}, 3));   // 2
        System.out.println(subarraySum(new int[]{-1,1,1}, 2)); // 1
        System.out.println("O(n) time, O(n) space — prefix sum + HashMap");
        System.out.println("Note: sliding window fails with negatives!");
    }
}

