import java.util.*;
public class FruitBaskets {
    public static int totalFruit(int[] fruits) {
        Map<Integer,Integer> basket = new HashMap<>(); // type → count
        int lo = 0, maxFruits = 0;
        for (int hi = 0; hi < fruits.length; hi++) {
            int f = fruits[hi];
            basket.put(f, basket.getOrDefault(f, 0) + 1); // add to basket
            // More than 2 types: shrink from left
            while (basket.size() > 2) {
                int left = fruits[lo];
                basket.put(left, basket.get(left) - 1);
                if (basket.get(left) == 0) basket.remove(left);
                lo++;
            }
            maxFruits = Math.max(maxFruits, hi - lo + 1);
        }
        return maxFruits;
    }
    public static void main(String[] args) {
        System.out.println(totalFruit(new int[]{1,2,1}));     // 3
        System.out.println(totalFruit(new int[]{0,1,2,2}));   // 3
        System.out.println(totalFruit(new int[]{1,2,3,2,2})); // 4
        System.out.println("O(n) — same as 'at most 2 distinct' sliding window");
    }
}

