public class MaxPointsKStudents {
    public static int maxScore(int[] cardPoints, int k) { return 0; }
    public static void main(String[] args) {
        System.out.println(maxScore(new int[]{1,2,3,4,5,6,1}, 3)); // 12
        System.out.println(maxScore(new int[]{9,7,7,9,7,7,9}, 7)); // 55
        System.out.println(maxScore(new int[]{1,1000,1}, 1));       // 1
    }
}

exercises.expected_solution:
public class MaxPointsKStudents {
    public static int maxScore(int[] cardPoints, int k) {
        int n = cardPoints.length;
        int total = 0;
        for (int p : cardPoints) total += p;
        // If k == n, take all cards:
        if (k == n) return total;
        // Find minimum sum window of size (n-k) = the middle we DON'T take
        int windowSize = n - k;
        int windowSum = 0;
        for (int i = 0; i < windowSize; i++) windowSum += cardPoints[i];
        int minWindow = windowSum;
        for (int i = windowSize; i < n; i++) {
            windowSum += cardPoints[i] - cardPoints[i - windowSize];
            minWindow = Math.min(minWindow, windowSum);
        }
        return total - minWindow; // take cards from both ends, skip middle
    }
    public static void main(String[] args) {
        System.out.println(maxScore(new int[]{1,2,3,4,5,6,1}, 3)); // 12
        System.out.println(maxScore(new int[]{9,7,7,9,7,7,9}, 7)); // 55
        System.out.println(maxScore(new int[]{1,1000,1}, 1));       // 1
        System.out.println("O(n) — sliding window on (n-k) middle");
        System.out.println("Key insight: max taken from ends = total - min(middle)");
    }
}

