public class LongestOnesAfterDelete {
    public static int longestSubarray(int[] nums) {
        int lo = 0, zeros = 0, maxLen = 0;
        for (int hi = 0; hi < nums.length; hi++) {
            if (nums[hi] == 0) zeros++;
            // More than 1 zero: shrink left
            while (zeros > 1) {
                if (nums[lo] == 0) zeros--;
                lo++;
            }
            // Window size - 1: we must delete exactly 1 element
            maxLen = Math.max(maxLen, hi - lo); // note: hi-lo NOT hi-lo+1
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(longestSubarray(new int[]{1,1,0,1}));           // 3
        System.out.println(longestSubarray(new int[]{0,1,1,1,0,1,1,0,1})); // 5
        System.out.println(longestSubarray(new int[]{1,1,1}));             // 2
        System.out.println("O(n) — at most 1 zero in window, answer = windowSize - 1");
    }
}

