import java.util.*;
public class SlidingWindowSynthesis {
    static int maxSumFixed(int[] nums, int k){
        int sum=0; for(int i=0;i<k;i++) sum+=nums[i];
        int max=sum;
        for(int i=k;i<nums.length;i++){sum+=nums[i]-nums[i-k];max=Math.max(max,sum);}
        return max;
    }
    static int longestNoRepeat(String s){
        Set<Character> w=new HashSet<>(); int lo=0,max=0;
        for(int hi=0;hi<s.length();hi++){while(w.contains(s.charAt(hi))) w.remove(s.charAt(lo++));w.add(s.charAt(hi));max=Math.max(max,hi-lo+1);}
        return max;
    }
    static int minSubarraySum(int target, int[] nums){
        int lo=0,sum=0,min=Integer.MAX_VALUE;
        for(int hi=0;hi<nums.length;hi++){sum+=nums[hi];while(sum>=target){min=Math.min(min,hi-lo+1);sum-=nums[lo++];}}
        return min==Integer.MAX_VALUE?0:min;
    }
    static List<Integer> findAnagrams(String s,String p){
        List<Integer> res=new ArrayList<>();if(s.length()<p.length())return res;
        int[] need=new int[26],have=new int[26],k=new int[]{p.length()};
        for(char c:p.toCharArray()) need[c-'a']++;
        for(int i=0;i<k[0];i++) have[s.charAt(i)-'a']++;
        if(Arrays.equals(need,have)) res.add(0);
        for(int i=k[0];i<s.length();i++){have[s.charAt(i)-'a']++;have[s.charAt(i-k[0])-'a']--;if(Arrays.equals(need,have)) res.add(i-k[0]+1);}
        return res;
    }
    public static void main(String[] args){
        System.out.println("1. maxSumFixed([2,3,4,1,5],2)=" + maxSumFixed(new int[]{2,3,4,1,5},2));
        System.out.println("2. longestNoRepeat('abcabcbb')=" + longestNoRepeat("abcabcbb"));
        System.out.println("3. minSubarraySum(7,[2,3,1,2,4,3])=" + minSubarraySum(7,new int[]{2,3,1,2,4,3}));
        System.out.println("4. findAnagrams('cbaebabacd','abc')=" + findAnagrams("cbaebabacd","abc"));
        boolean allPass = maxSumFixed(new int[]{2,3,4,1,5},2)==9
            && longestNoRepeat("abcabcbb")==3
            && minSubarraySum(7,new int[]{2,3,1,2,4,3})==2
            && findAnagrams("cbaebabacd","abc").equals(Arrays.asList(0,6));
        System.out.println("All pass: " + allPass);
    }
}
